    .quiz-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 24px; position: relative; }
    .quiz-progress { font-size: 0.95rem; color: #888; }
    .quiz-score { display: flex; gap: 16px; font-size: 1rem; }
    .score-item { display: flex; align-items: center; gap: 4px; }
    .progress-bar { width: 100%; height: 4px; background: var(--cloud); border-radius: 2px; margin-bottom: 24px; overflow: hidden; }
    .progress-fill { height: 100%; background: linear-gradient(90deg, var(--accent), var(--gold)); border-radius: 2px; transition: width 0.4s ease; }

