import { useState, useEffect, useCallback, useMemo, useRef } from "react";

// ─── Default Hanzi Data ───────────────────────────────────────────────
import DEFAULT_HANZI_DATA from "./data/hanziData.json";

// ─── Utility ───────────────────────────────────────────────────────────
function shuffle(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

function pickRandom(arr, n, exclude = []) {
  const filtered = arr.filter(x => !exclude.includes(x));
  return shuffle(filtered).slice(0, n);
}

// ─── App Component ─────────────────────────────────────────────────────
export default function HanziApp() {
  const [screen, setScreen] = useState("home"); // home | browse | quiz | import | history
  const [mode, setMode] = useState(null);

  const [timeLimit, setTimeLimit] = useState(180);
  const [timeLeft, setTimeLeft] = useState(0);
  const [isTimerRunning, setIsTimerRunning] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [questionCountLimit, setQuestionCountLimit] = useState(0);
  const [hasFirstTry, setHasFirstTry] = useState(true);
  const [radicalSearchQuery, setRadicalSearchQuery] = useState("");
  const [questionStartTime, setQuestionStartTime] = useState(0);
  const [responseTimes, setResponseTimes] = useState([]);
  const timerRef = useRef(null);

  const [history, setHistory] = useState(() => {
    try {
      const saved = localStorage.getItem("hanziHistory");
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      return [];
    }
  });

  // ─── Custom Data & LocalStorage Logic ───
  const [customData, setCustomData] = useState(() => {
    try {
      const saved = localStorage.getItem("customHanzi");
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      return [];
    }
  });

  const [importText, setImportText] = useState("");

  const [selectedLevel, setSelectedLevel] = useState(1);

  const hanziData = useMemo(() => {
    return [...DEFAULT_HANZI_DATA, ...customData];
  }, [customData]);

  const charLevelMap = useMemo(() => {
    const map = new Map();
    hanziData.forEach(h => {
      if (h.level) map.set(h.char, h.level);
    });
    return map;
  }, [hanziData]);

  const levelData = useMemo(() => {
    return hanziData.filter(h => !h.level || h.level <= selectedLevel);
  }, [hanziData, selectedLevel]);

  const allRadicals = useMemo(() => {
    return [...new Set(levelData.map(h => h.radical).filter(Boolean))];
  }, [levelData]);

  const [selectedRadicals, setSelectedRadicals] = useState(() => {
    return new Set(pickRandom(allRadicals, 5));
  });

  useEffect(() => {
    setSelectedRadicals(new Set(pickRandom(allRadicals, 5)));
    setRadicalSearchQuery("");
  }, [allRadicals]);

  const filteredAllRadicals = useMemo(() => {
    if (!radicalSearchQuery) return allRadicals;
    return allRadicals.filter(r => r.includes(radicalSearchQuery));
  }, [allRadicals, radicalSearchQuery]);

  // ─── Quiz States ───
  const [quizPool, setQuizPool] = useState([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [options, setOptions] = useState([]);
  const [selected, setSelected] = useState(null);
  const [correct, setCorrect] = useState(null);
  const [score, setScore] = useState(0);
  const [total, setTotal] = useState(0);
  const [showResult, setShowResult] = useState(false);
  const [browseRadical, setBrowseRadical] = useState(allRadicals[0]);
  const [flipCard, setFlipCard] = useState(null);
  const [wordBlank, setWordBlank] = useState(null);
  const [streak, setStreak] = useState(0);
  const [bestStreak, setBestStreak] = useState(0);
  const [wrongAttempts, setWrongAttempts] = useState([]);
  const [animKey, setAnimKey] = useState(0);

  const filteredData = levelData.filter(h => selectedRadicals.has(h.radical));

  // ─── Timer Logic ───
  const endQuiz = useCallback(() => {
    setIsTimerRunning(false);
    setShowResult(true);
  }, []);

  useEffect(() => {
    if (screen === "quiz" && !showResult && isTimerRunning && timeLimit > 0 && !isPaused) {
      timerRef.current = setInterval(() => {
        setTimeLeft(prev => {
          if (prev <= 1) {
            clearInterval(timerRef.current);
            endQuiz();
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    }
    return () => clearInterval(timerRef.current);
  }, [screen, showResult, isTimerRunning, timeLimit, isPaused, endQuiz]);

  useEffect(() => {
    if (showResult && screen === "quiz") {
      setHistory(prev => {
        if (prev.length > 0 && prev[0].date && (Date.now() - new Date(prev[0].date).getTime() < 2000)) {
          return prev;
        }
        const newHistory = { date: new Date().toISOString(), mode, timeLimit, score, total };
        const updatedHistory = [newHistory, ...prev].slice(0, 100);
        localStorage.setItem("hanziHistory", JSON.stringify(updatedHistory));
        return updatedHistory;
      });
    }
  }, [showResult, screen, mode, timeLimit, score, total]);

  const topSlowest = useMemo(() => {
    if (responseTimes.length === 0) return [];
    const charTimes = {};
    responseTimes.forEach(rt => {
      if (!charTimes[rt.char]) charTimes[rt.char] = { sum: 0, count: 0 };
      charTimes[rt.char].sum += rt.time;
      charTimes[rt.char].count += 1;
    });
    const avgTimes = Object.keys(charTimes).map(char => ({
      char,
      avgTime: charTimes[char].sum / charTimes[char].count
    }));
    avgTimes.sort((a, b) => b.avgTime - a.avgTime);
    return avgTimes.slice(0, 5);
  }, [responseTimes]);

  // ─── Import Functions ───
  const handleImport = () => {
    if (!importText.trim()) return alert("請輸入內容！");

    const lines = importText.split("\n");
    const newItems = [];

    for (const line of lines) {
      const trimmed = line.trim();
      if (!trimmed) continue;

      let parts = [];
      const isMdTable = trimmed.startsWith('|') && trimmed.endsWith('|');

      if (isMdTable) {
        parts = trimmed.split('|').map(s => s.trim()).filter(s => s);
        // 略過標題列與分隔線
        if (parts.length === 0 || parts[0] === '漢字' || parts[0].includes('---')) continue;
      } else {
        parts = trimmed.split(",").map(s => s.trim());
      }

      // 確保格式符合：漢字,注音,拼音,造詞1/造詞2,部首
      if (parts.length >= 4) {
        newItems.push({
          char: parts[0],
          zhuyin: parts[1],
          pinyin: parts[2],
          words: parts[3].split("/").map(w => w.trim()).filter(w => w),
          radical: parts[4] || "自訂"
        });
      }
    }

    if (newItems.length === 0) {
      return alert("格式不正確或沒有可匯入的單字。請確認格式為：漢字,注音,拼音,造詞1/造詞2,部首 (或使用 Markdown 表格)");
    }

    const updatedCustom = [...customData, ...newItems];
    setCustomData(updatedCustom);
    localStorage.setItem("customHanzi", JSON.stringify(updatedCustom));
    setImportText("");
    alert(`成功匯入 ${newItems.length} 個單字！`);
    setScreen("home");
  };

  const handleClearCustom = () => {
    if (window.confirm("確定要清除所有自訂單字嗎？")) {
      setCustomData([]);
      localStorage.removeItem("customHanzi");
      alert("自訂題庫已清除！");
    }
  };

  // ─── Quiz Functions ───
  const startQuiz = (m, isCustom = false) => {
    let pool = filteredData;
    if (isCustom) {
      pool = hanziData; // "全字庫"
      const countStr = prompt("請輸入挑戰題數 (例如 50)", "50");
      if (!countStr) return;
      const count = parseInt(countStr, 10);
      if (isNaN(count) || count <= 0) return alert("無效的題數");
      setQuestionCountLimit(count);
      setTimeLimit(0); // 無時間限制
    } else {
      setQuestionCountLimit(0);
      if (filteredData.length < 3) {
        return alert("題庫字數太少，請至少勾選包含 3 個字以上的部首！");
      }
    }
    pool = shuffle(pool);
    setMode(m);
    setQuizPool(pool);
    setCurrentIdx(0);
    setScore(0);
    setTotal(0);
    setSelected(null);
    setCorrect(null);
    setShowResult(false);
    setStreak(0);
    setBestStreak(0);
    setScreen("quiz");
    setResponseTimes([]);
    setTimeLeft(isCustom ? 0 : timeLimit);
    setIsTimerRunning(true);
    setIsPaused(false);
    setHasFirstTry(true);
    setWrongAttempts([]);
    generateQuestion(pool, 0, m, isCustom);
  };

  const generateQuestion = useCallback((pool, idx, m, isCustom = false) => {
    const activeMode = isCustom ? Math.floor(Math.random() * 3) + 1 : m;
    const currentPoolIdx = idx % pool.length;
    let activePool = pool;
    if (idx > 0 && currentPoolIdx === 0) {
      activePool = shuffle([...pool]);
      setQuizPool(activePool);
    }
    const item = activePool[currentPoolIdx];
    setAnimKey(k => k + 1);
    setQuestionStartTime(Date.now());
    setHasFirstTry(true);
    setSelected(null);
    setCorrect(null);
    setWrongAttempts([]);
    setMode(activeMode); // 為了讓 handleSelect 知道題型

    if (activeMode === 1) {
      const wrongs = pickRandom(hanziData.map(h => h.zhuyin), 2, [item.zhuyin]);
      setOptions(shuffle([item.zhuyin, ...wrongs]));
    } else if (activeMode === 2) {
      const wrongs = pickRandom(hanziData.map(h => h.char), 2, [item.char]);
      setOptions(shuffle([item.char, ...wrongs]));
    } else if (activeMode === 3) {
      // 確保造詞中一定要包含目標字，避免出「同『某』」這種無法填空的題目
      let candidateWords = item.words.filter(w => w.includes(item.char));

      // 史萊姆(1) 到 巫妖(4) 等級：為了新手學習，嚴格只使用長度為 2~4 的造詞
      if (!isCustom && selectedLevel <= 4) {
        candidateWords = candidateWords.filter(w => w.length >= 2 && w.length <= 4);

        // 史萊姆(1) 到 飛龍(3) 等級：再進一步過濾掉包含困難字 (等級大於3) 的造詞
        if (selectedLevel <= 3) {
          candidateWords = candidateWords.filter(word => {
            for (let char of word) {
              // 標點符號不予理會，但如果是中文字且字典內沒有/等級太高，就排除
              const lvl = charLevelMap.get(char);
              if (lvl && lvl > 3) return false;
            }
            return true;
          });
        }
      }

      // 如果過濾後沒有造詞，就只使用單字來出題（會變成單純的看音選字，以符合字數限制）
      if (candidateWords.length === 0) {
        candidateWords = [item.char];
      }

      const word = candidateWords[Math.floor(Math.random() * candidateWords.length)];
      if (word) {
        const charIdx = word.indexOf(item.char);
        const blanked = charIdx !== -1
          ? word.substring(0, charIdx) + "＿" + word.substring(charIdx + 1)
          : "＿"; // fallback 如果還是找不到就只出底線
        setWordBlank(blanked);
      } else {
        setWordBlank("＿");
      }
      const wrongs = pickRandom(hanziData.map(h => h.char), 2, [item.char]);
      setOptions(shuffle([item.char, ...wrongs]));
    }
  }, [hanziData, selectedLevel, charLevelMap]);

  const handleSelect = (opt) => {
    if (selected !== null && correct) return; // 已答對，等待跳題時不反應
    if (wrongAttempts.includes(opt)) return; // 已經選過的錯誤選項不反應

    const item = quizPool[currentIdx % quizPool.length];
    let isCorrect;
    if (mode === 1) isCorrect = opt === item.zhuyin;
    else if (mode === 2) isCorrect = opt === item.char;
    else isCorrect = opt === item.char;

    if (isCorrect) {
      const timeSpent = Date.now() - questionStartTime;
      setResponseTimes(prev => [...prev, { char: item.char, time: timeSpent }]);
      setSelected(opt);
      setCorrect(true);

      if (hasFirstTry) {
        setScore(s => s + 1);
        setStreak(s => {
          const ns = s + 1;
          setBestStreak(b => Math.max(b, ns));
          return ns;
        });
      }

      const newTotal = total + 1;
      setTotal(newTotal);

      // check if challenge mode ended
      if (questionCountLimit > 0 && newTotal >= questionCountLimit) {
        setTimeout(() => endQuiz(), 800);
      } else {
        setTimeout(() => {
          const next = currentIdx + 1;
          setCurrentIdx(next);
          generateQuestion(quizPool, next, questionCountLimit > 0 ? 0 : mode, questionCountLimit > 0);
        }, 800);
      }
    } else {
      setWrongAttempts(prev => [...prev, opt]);
      setHasFirstTry(false);
      setStreak(0);
    }
  };

  const toggleRadical = (r) => {
    setSelectedRadicals(prev => {
      const next = new Set(prev);
      if (next.has(r)) next.delete(r);
      else next.add(r);
      return next;
    });
  };

  const selectAll = () => setSelectedRadicals(new Set(allRadicals));
  const clearAll = () => setSelectedRadicals(new Set());

  // 確保瀏覽部首存在，若無則切回第一個
  const currentBrowseRadical = allRadicals.includes(browseRadical) ? browseRadical : allRadicals[0];
  const browseCards = hanziData.filter(h => h.radical === currentBrowseRadical);

  // ─── Styles ──────────────────────────────────────────────────────────
  const css = `
    @import url('https://fonts.googleapis.com/css2?family=Noto+Serif+TC:wght@600;900&display=swap');

    @font-face {
      font-family: 'Iansui';
      src: url('https://cdn.jsdelivr.net/gh/buttaiwan/iansui@master/Iansui-Regular.ttf') format('truetype');
      font-weight: 400;
      font-style: normal;
      font-display: swap;
    }

    :root {
      --ink: #1a1a2e;
      --paper: #faf7f0;
      --accent: #c0392b;
      --accent2: #e74c3c;
      --gold: #d4a017;
      --jade: #1a8a5c;
      --jade-light: #2ecc71;
      --cloud: #ecf0f1;
      --mist: #dfe6e9;
      --shadow: rgba(26, 26, 46, 0.08);
      --correct: #27ae60;
      --wrong: #e74c3c;
    }

    * { box-sizing: border-box; margin: 0; padding: 0; }

    body {
      font-family: 'Iansui', sans-serif;
      background: var(--paper);
      color: var(--ink);
      min-height: 100vh;
    }

    h1, h2, h3, .big-char, .prompt-char, .prompt-word {
      font-family: 'Noto Serif TC', serif;
    }

    .app {
      max-width: 520px;
      margin: 0 auto;
      padding: 16px;
      min-height: 100vh;
    }

    /* ─── Header ─── */
    .header {
      text-align: center;
      padding: 32px 0 24px;
      position: relative;
    }

    .header h1 {
      font-size: 2.4rem;
      color: var(--accent);
      letter-spacing: 4px;
      position: relative;
      display: inline-block;
      font-weight: 900;
    }

    .header h1::after {
      content: '';
      display: block;
      width: 60%;
      height: 3px;
      background: linear-gradient(90deg, transparent, var(--gold), transparent);
      margin: 8px auto 0;
    }

    .subtitle {
      font-size: 0.9rem;
      color: #888;
      margin-top: 8px;
      letter-spacing: 2px;
    }

    .back-btn {
      position: absolute;
      left: 0;
      top: 50%;
      transform: translateY(-50%);
      background: none;
      border: none;
      font-size: 1.5rem;
      cursor: pointer;
      color: var(--ink);
      padding: 8px;
      transition: transform 0.2s;
    }

    .back-btn:hover { transform: translateY(-50%) scale(1.2); }

    /* ─── Home ─── */
    .home-grid {
      display: flex;
      flex-direction: column;
      gap: 16px;
      margin-top: 24px;
    }

    .mode-card {
      background: white;
      border-radius: 16px;
      padding: 24px;
      cursor: pointer;
      border: 2px solid transparent;
      transition: all 0.3s;
      position: relative;
      overflow: hidden;
    }

    .mode-card::before {
      content: '';
      position: absolute;
      top: 0; left: 0; right: 0;
      height: 4px;
    }

    .mode-card:nth-child(1)::before { background: var(--accent); }
    .mode-card:nth-child(2)::before { background: var(--jade); }
    .mode-card:nth-child(3)::before { background: var(--gold); }
    .mode-card:nth-child(4)::before { background: var(--ink); }
    .mode-card:nth-child(5)::before { background: #8e44ad; }

    .mode-card:hover {
      transform: translateY(-4px);
      box-shadow: 0 12px 32px var(--shadow);
      border-color: var(--mist);
    }

    .mode-card .mode-icon {
      font-size: 2rem;
      margin-bottom: 8px;
    }

    .mode-card h3 {
      font-size: 1.25rem;
      margin-bottom: 6px;
    }

    .mode-card p {
      font-size: 1rem;
      color: #666;
      line-height: 1.6;
    }

    .mode-tag {
      display: inline-block;
      padding: 2px 10px;
      border-radius: 999px;
      font-size: 0.85rem;
      margin-bottom: 8px;
    }

    .tag-red { background: #fce4e4; color: var(--accent); }
    .tag-green { background: #e4f9e8; color: var(--jade); }
    .tag-gold { background: #fff8e1; color: #b8860b; }
    .tag-dark { background: #eee; color: var(--ink); }
    .tag-purple { background: #f5eef8; color: #8e44ad; }

    /* ─── Radical Filter ─── */
    .radical-section {
      margin-top: 32px;
      padding: 20px;
      background: white;
      border-radius: 16px;
    }

    .radical-section h4 {
      font-size: 1.1rem;
      margin-bottom: 12px;
      display: flex;
      justify-content: space-between;
      align-items: center;
      font-family: 'Noto Serif TC', serif;
    }

    .radical-chips {
      display: flex;
      flex-wrap: wrap;
      gap: 8px;
    }

    .radical-chip {
      padding: 6px 14px;
      border-radius: 999px;
      border: 1.5px solid var(--mist);
      background: var(--cloud);
      font-size: 1rem;
      cursor: pointer;
      transition: all 0.2s;
      font-family: inherit;
    }

    .radical-chip.on {
      background: var(--ink);
      color: white;
      border-color: var(--ink);
    }

    .radical-chip:hover { border-color: var(--accent); }

    .chip-actions {
      display: flex;
      gap: 8px;
    }

    .chip-actions button {
      background: none;
      border: none;
      color: var(--accent);
      font-size: 0.95rem;
      cursor: pointer;
      font-family: inherit;
    }

    /* ─── Import Screen ─── */
    .import-card {
      background: white;
      padding: 24px;
      border-radius: 16px;
      margin-top: 16px;
      box-shadow: 0 4px 12px var(--shadow);
    }

    .import-card p {
      line-height: 1.6;
      color: #555;
      margin-bottom: 12px;
      font-size: 1rem;
    }

    .import-code {
      display: block;
      background: #eee;
      padding: 12px;
      border-radius: 8px;
      font-family: monospace;
      color: #333;
      margin: 8px 0;
      font-size: 0.9rem;
    }

    .import-textarea {
